import React, { useState } from 'react';
const Test2912 = () => {
    const [result, setResult] = useState<number>(1)
    const [myNumber, setMyNumber] = useState<number>(0)
    const [renderCount, setRenderCount] = useState<number>(0);
    React.useEffect(() => {
        setRenderCount(renderCount + 1);
        console.log(`Component has rendered ${renderCount} times`);
    });
    const handleCalculate = () => {
        let product = 1;
        for (let i = 1; i <= myNumber; i++) {
            product *= i;
        }
        setResult(product);
    }
    return (
        <div>
            <h1>Practicing useRef with React</h1>
            <input type="number" id="myNumber" value={myNumber}
            onChange={(e) => setMyNumber(Number(e.currentTarget.value))}
            />
            <button id="myButton" onClick={handleCalculate}>Tính</button>
            <p id="ketqua">{result}</p>
            <p id="renderCount">Render Count: {renderCount}</p>
        </div>
    );
}
export default Test2912;
